# Python 3.11+
"""Seat-allocation policies — the seam that decides WHICH seats to hold when a
user asks for "N seats" instead of naming them.

🎙️ "The booking service doesn't hardcode how to pick seats. It asks a
SeatAllocationStrategy. Today best-available and contiguous; tomorrow
'cheapest first' or 'aisle-preferred' — each is a new class, zero service
changes."
"""

from abc import ABC, abstractmethod
from collections import defaultdict

from models import InvalidSeatError, SeatUnavailableError, ShowSeat


class SeatAllocationStrategy(ABC):
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # The abstraction BookingService depends on (Dependency Inversion). It is
    # handed the list of currently-free seats and a count, and returns exactly
    # which seat ids to hold — or raises if it can't satisfy the request.
    @abstractmethod
    def select(self, available: list[ShowSeat], count: int) -> list[str]:
        """Pick `count` seat ids from `available`, or raise SeatUnavailableError."""
        raise NotImplementedError


class BestAvailableStrategy(SeatAllocationStrategy):
    """Fill from the front: lowest (row, number) first. Simple and fair (default)."""

    def select(self, available: list[ShowSeat], count: int) -> list[str]:
        if count < 1:
            raise InvalidSeatError("count must be >= 1")
        # WHY: sort by (row, number) so the choice is deterministic — tests and
        #      humans can predict exactly which seats come back.
        ordered = sorted(available, key=lambda s: (s.row, s.number))
        if len(ordered) < count:
            raise SeatUnavailableError(f"only {len(ordered)} seats free, need {count}")
        return [seat.id for seat in ordered[:count]]


class ContiguousStrategy(SeatAllocationStrategy):
    """Keep a group together: find `count` adjacent seats in a single row."""

    def select(self, available: list[ShowSeat], count: int) -> list[str]:
        if count < 1:
            raise InvalidSeatError("count must be >= 1")
        by_row: dict[str, list[ShowSeat]] = defaultdict(list)
        for seat in available:
            by_row[seat.row].append(seat)

        for row in sorted(by_row):
            seats = sorted(by_row[row], key=lambda s: s.number)
            run: list[ShowSeat] = []

            for seat in seats:
                # WHY: extend the current run only when seat numbers are exactly
                #      consecutive; any gap resets the run to start at this seat.
                if run and seat.number == run[-1].number + 1:
                    run.append(seat)
                else:
                    run = [seat]

                if len(run) == count:
                    return [s.id for s in run]

        raise SeatUnavailableError(f"no block of {count} contiguous seats is available")

